const ocp = (appts || []).map(a => a.scheduled_at.slice(11, 16));
const slots = [];
for (const a of avail) {
  const parts = a.start_time.split(':');
  const eparts = a.end_time.split(':');
  let c = parseInt(parts[0]) * 60 + parseInt(parts[1]);
  const e = parseInt(eparts[0]) * 60 + parseInt(eparts[1]);
  while (c + 30 <= e) {
    const h = String(Math.floor(c / 60)).padStart(2, '0');
    const m = String(c % 60).padStart(2, '0');
    if (!ocp.includes(h + ':' + m)) slots.push(h + ':' + m);
    c += 30;
  }
}
if (slots.length === 0) return 'Sem horários disponíveis em ' + data + '.';
return 'Horários disponíveis em ' + data + ':\n' + slots.join('\n');

